INSERT INTO rooms (organization_id, room_number, floor, room_type, row_segmented, is_active, vip_tier) SELECT o.id, 'Private 2', 2, 'PRIVATE', false, true, NULL FROM organizations o WHERE o.slug='lasema' AND NOT EXISTS (SELECT 1 FROM rooms r WHERE r.organization_id=o.id AND r.room_number='Private 2');
